// Import Cassandra connector
import org.apache.spark.sql.cassandra._

// Configuration for Cassandra connection
val cassandraHost = "127.0.0.1"
val cassandraPort = 9042

println(s"Attempting to connect to Cassandra at $cassandraHost:$cassandraPort")

// Set Spark Cassandra connector configuration
spark.conf.set("spark.cassandra.connection.host", cassandraHost)
spark.conf.set("spark.cassandra.connection.port", cassandraPort)

// Method: Use raw CQL via spark.sql to create keyspace
try {
  spark.sql("CREATE DATABASE IF NOT EXISTS movielens")
  println("Keyspace 'movielens' created/verified")
} catch {
  case e: Exception => println(s"Keyspace creation note: ${e.getMessage.take(100)}")
