// ============================================
// First, check actual column names
// ============================================
println("Checking actual DataFrame schemas:")

println("\n--- userFavoriteGenreDF ---")
userFavoriteGenreDF.printSchema()
println("Columns: " + userFavoriteGenreDF.columns.mkString(", "))

println("\n--- top10MoviesDF ---")
top10MoviesDF.printSchema()

println("\n--- youngUsersDF ---")
youngUsersDF.printSchema()

println("\n--- scientistUsersDF ---")
scientistUsersDF.printSchema()

// ============================================
// Prepare data for Cassandra with correct column names
// ============================================

// 1. Top movies data - column names: title, avg_rating, rating_count
val topMoviesForCassandra = top10MoviesDF.select(
  col("title").as("movie_title"), 
  col("avg_rating"), 
  col("rating_count")
)

println("\n1. Top movies data prepared:")
topMoviesForCassandra.show(5, false)

// 2. User favorite genre - ONLY use columns that exist
// Actual columns: user_id, genre, favorite_genre_count
// Cassandra table expects: user_id, genre, genre_rating_count, total_ratings
// We'll create total_ratings as NULL or 0 for now
val userGenreForCassandra = userFavoriteGenreDF.select(
  col("user_id"),
  col("genre"),
  col("favorite_genre_count").as("genre_rating_count"),
  lit(0).as("total_ratings")  // Add a default total_ratings column
)

println("\n2. User genre data prepared:")
userGenreForCassandra.printSchema()
userGenreForCassandra.show(5, false)

// 3. User info with categories
val youngWithCategory = youngUsersDF.withColumn("user_category", lit("young"))
val scientistWithCategory = scientistUsersDF.withColumn("user_category", lit("scientist_30_40"))
val userInfoForCassandra = youngWithCategory.union(scientistWithCategory).distinct()
  .select("user_id", "age", "gender", "occupation", "zip_code", "user_category")

println("\n3. User info data prepared:")
userInfoForCassandra.printSchema()
userInfoForCassandra.show(5, false)

println("\nData counts for Cassandra write:")
println(s"  - top_movies: ${topMoviesForCassandra.count()} records")
println(s"  - user_favorite_genre: ${userGenreForCassandra.count()} records")
println(s"  - user_info: ${userInfoForCassandra.count()} records")

// ============================================
// Write to Cassandra
// ============================================

try {
  // Write top movies
  topMoviesForCassandra.write
    .format("org.apache.spark.sql.cassandra")
    .mode("append")
    .options(Map("keyspace" -> "movielens", "table" -> "top_movies"))
    .save()
  println("✓ Written to top_movies")
  
  // Write user favorite genre
  userGenreForCassandra.write
    .format("org.apache.spark.sql.cassandra")
    .mode("append")
    .options(Map("keyspace" -> "movielens", "table" -> "user_favorite_genre"))
    .save()
  println("✓ Written to user_favorite_genre")
  
  // Write user info
  userInfoForCassandra.write
    .format("org.apache.spark.sql.cassandra")
    .mode("append")
    .options(Map("keyspace" -> "movielens", "table" -> "user_info"))
    .save()
  println("✓ Written to user_info")
  
  println("\n✓✓✓ All data successfully written to Cassandra!")
  
} catch {
  case e: Exception => println(s"Error writing to Cassandra: ${e.getMessage}")
  println("\nNote: If Cassandra is not running, the data was not written.")
  println("The DataFrames are still available for viewing below.")
}

// ============================================
// Verify the data was written by reading it back
// ============================================
println("\n" + "="*60)
println("VERIFYING CASSANDRA WRITE")
println("="*60)

try {
  val verifyTopMovies = spark.read
    .format("org.apache.spark.sql.cassandra")
    .options(Map("keyspace" -> "movielens", "table" -> "top_movies"))
    .load()
  
  println("\nData in Cassandra - top_movies:")
  verifyTopMovies.show(10, false)
  
  val verifyUserGenres = spark.read
    .format("org.apache.spark.sql.cassandra")
    .options(Map("keyspace" -> "movielens", "table" -> "user_favorite_genre"))
    .load()
  
  println("\nData in Cassandra - user_favorite_genre (first 10):")
  verifyUserGenres.show(10, false)
  
  val verifyUserInfo = spark.read
    .format("org.apache.spark.sql.cassandra")
    .options(Map("keyspace" -> "movielens", "table" -> "user_info"))
    .load()
  
  println("\nData in Cassandra - user_info:")
  verifyUserInfo.show(10, false)
  
} catch {
  case e: Exception => println(s"Could not verify Cassandra data: ${e.getMessage}")
}

