// ============================================
// Helper function for ASCII bar chart
// ============================================
def printBarChart(data: Array[(String, Double)], title: String, maxWidth: Int = 50): Unit = {
  println("\n" + title)
  println("-" * 65)
  
  val maxValue = data.map(_._2).max
  val scale = maxWidth / maxValue
  
  for ((label, value) <- data) {
    val barLength = (value * scale).toInt
    val bar = "█" * barLength
    val truncatedLabel = if (label.length > 35) label.take(32) + "..." else label
    println(f"${truncatedLabel}%-38s | ${bar} ${value}%.2f")
  }
}

def printDistribution[T](data: Array[(T, Long)], title: String, maxWidth: Int = 40): Unit = {
  println("\n" + title)
  println("-" * 65)
  
  val maxValue = data.map(_._2).max.toDouble
  val scale = maxWidth / maxValue
  
  for ((key, value) <- data.take(20)) {
    val barLength = (value * scale).toInt
    val bar = "█" * barLength
    println(f"${key}%-10s | ${bar} ${value}")
  }
}

