println("\n[STEP 1] Exporting DataFrames to CSV format...")

val hbaseTempDir = "/tmp/hbase_import"
import java.io.File
def deleteDir(dir: File): Unit = {
  if (dir.exists()) {
    dir.listFiles().foreach { f =>
      if (f.isDirectory) deleteDir(f) else f.delete()
    }
    dir.delete()
  }
}
deleteDir(new File(hbaseTempDir))
new File(hbaseTempDir).mkdirs()

// Export top 10 movies
top10MoviesDF.select(
  col("title").as("movie_title"),
  col("avg_rating"),
  col("rating_count")
).coalesce(1).write.mode("overwrite").option("header", "true").csv(s"$hbaseTempDir/top_movies")
println("  ✓ Exported top_movies")

// Export user favorite genre
userFavoriteGenreDF.coalesce(1).write.mode("overwrite").option("header", "true").csv(s"$hbaseTempDir/user_genres")
println("  ✓ Exported user_genres")

// Export young users
